#include <iostream>
#include <string>

void swap(int* a, int* b) {
    // Pointer parameters — can modify caller's variables
    int temp = *a;
    *a = *b;
    *b = temp;
}

void swapRef(int& a, int& b) {
    // Reference parameters — cleaner syntax, same effect
    int temp = a;
    a = b;
    b = temp;
}

void printArray(const int* arr, int size) {
    // const pointer — read-only access
    for (int i = 0; i < size; i++) {
        std::cout << arr[i] << " ";
    }
    std::cout << std::endl;
}

int main() {
    // Raw pointers
    int x = 10;
    int* ptr = &x;          // & gets address
    std::cout << "Value: " << *ptr << std::endl;  // * dereferences
    std::cout << "Address: " << ptr << std::endl;

    *ptr = 20;  // Modify through pointer
    std::cout << "x after pointer modification: " << x << std::endl;

    // Pointer arithmetic
    int arr[] = {10, 20, 30, 40, 50};
    int* p = arr;  // Array name is a pointer to first element
    std::cout << "\nPointer arithmetic:\n";
    for (int i = 0; i < 5; i++) {
        std::cout << "  *(p+" << i << ") = " << *(p + i) << std::endl;
    }

    // Swap with pointers
    int a = 5, b = 10;
    std::cout << "\nBefore swap: a=" << a << " b=" << b << std::endl;
    swap(&a, &b);  // Pass addresses
    std::cout << "After pointer swap: a=" << a << " b=" << b << std::endl;

    // Swap with references (cleaner)
    swapRef(a, b);
    std::cout << "After ref swap: a=" << a << " b=" << b << std::endl;

    // Null pointer safety
    int* np = nullptr;
    if (np != nullptr) {
        std::cout << *np << std::endl;  // Won't execute
    } else {
        std::cout << "\nPointer is null — safe check" << std::endl;
    }

    // Dynamic allocation with pointers
    int* dynamic = new int(42);
    std::cout << "Dynamic value: " << *dynamic << std::endl;
    delete dynamic;
    dynamic = nullptr;  // Avoid dangling pointer

    return 0;
}
