#include <iostream>
#include <string>
#include <vector>
#include <memory>

class Shape {
protected:
    std::string name;
public:
    Shape(const std::string& name) : name(name) {}
    virtual ~Shape() = default;  // Virtual destructor for polymorphism

    // Pure virtual — must be implemented by derived classes
    virtual double area() const = 0;
    virtual double perimeter() const = 0;

    // Virtual with default implementation
    virtual void describe() const {
        std::cout << name << ": area=" << area() << ", perimeter=" << perimeter() << std::endl;
    }

    const std::string& getName() const { return name; }
};

class Circle : public Shape {
private:
    double radius;
public:
    Circle(double r) : Shape("Circle"), radius(r) {}

    double area() const override { return 3.14159 * radius * radius; }
    double perimeter() const override { return 2 * 3.14159 * radius; }
};

class Rectangle : public Shape {
private:
    double width, height;
public:
    Rectangle(double w, double h) : Shape("Rectangle"), width(w), height(h) {}

    double area() const override { return width * height; }
    double perimeter() const override { return 2 * (width + height); }
};

class Square : public Rectangle {
public:
    Square(double side) : Rectangle(side, side) {
        name = "Square";
    }
};

int main() {
    // Polymorphism through base class pointers
    std::vector<std::unique_ptr<Shape>> shapes;
    shapes.push_back(std::make_unique<Circle>(5.0));
    shapes.push_back(std::make_unique<Rectangle>(4.0, 6.0));
    shapes.push_back(std::make_unique<Square>(3.0));

    // Virtual dispatch calls the correct derived method
    double totalArea = 0;
    for (const auto& shape : shapes) {
        shape->describe();
        totalArea += shape->area();
    }
    std::cout << "\nTotal area: " << totalArea << std::endl;

    // dynamic_cast for safe downcasting
    Shape* s = shapes[0].get();
    if (Circle* c = dynamic_cast<Circle*>(s)) {
        std::cout << "\nCircle radius check: " << c->area() / 3.14159 << std::endl;
    }

    return 0;
}
