#include <iostream>
#include <vector>
#include <map>
#include <unordered_map>
#include <set>
#include <algorithm>
#include <string>

struct Student {
    std::string name;
    int age;
    double gpa;

    // For set/map ordering
    bool operator<(const Student& other) const {
        return gpa < other.gpa;
    }
};

int main() {
    // vector — dynamic array, O(1) random access
    std::vector<int> nums = {5, 2, 8, 1, 9, 3};
    nums.push_back(7);
    nums.pop_back();
    std::sort(nums.begin(), nums.end());
    std::cout << "Sorted vector: ";
    for (int n : nums) std::cout << n << " ";
    std::cout << "\nSize: " << nums.size() << ", Capacity: " << nums.capacity() << std::endl;

    // map — sorted key-value, O(log n)
    std::map<std::string, int> ages;
    ages["Alice"] = 25;
    ages["Bob"] = 30;
    ages["Charlie"] = 22;
    ages.insert({"Diana", 28});

    std::cout << "\nSorted map:\n";
    for (const auto& [name, age] : ages) {
        std::cout << "  " << name << ": " << age << std::endl;
    }

    // unordered_map — hash table, O(1) average
    std::unordered_map<std::string, double> grades;
    grades["Math"] = 95.5;
    grades["Science"] = 88.0;
    grades["English"] = 92.3;

    std::cout << "\nUnordered map (fast lookup):\n";
    for (const auto& [subject, grade] : grades) {
        std::cout << "  " << subject << ": " << grade << std::endl;
    }
    std::cout << "Math grade: " << grades["Math"] << std::endl;

    // set — unique elements, sorted
    std::set<int> uniqueNums(nums.begin(), nums.end());
    uniqueNums.insert(5);  // Duplicate — ignored
    std::cout << "\nSet (unique): ";
    for (int n : uniqueNums) std::cout << n << " ";
    std::cout << std::endl;

    // STL algorithms
    auto it = std::find(nums.begin(), nums.end(), 8);
    if (it != nums.end()) {
        std::cout << "\nFound 8 at index: " << std::distance(nums.begin(), it) << std::endl;
    }

    int count = std::count_if(nums.begin(), nums.end(), [](int n) { return n > 5; });
    std::cout << "Numbers > 5: " << count << std::endl;

    return 0;
}
