#include <iostream>
#include <string>
#include <vector>
#include <concepts>

// Function template
template<typename T>
T max_val(T a, T b) {
    return (a > b) ? a : b;
}

// Class template
template<typename T>
class Stack {
private:
    std::vector<T> elements;
public:
    void push(const T& item) {
        elements.push_back(item);
    }

    T pop() {
        if (elements.empty()) throw std::runtime_error("Stack is empty");
        T top = elements.back();
        elements.pop_back();
        return top;
    }

    const T& peek() const {
        if (elements.empty()) throw std::runtime_error("Stack is empty");
        return elements.back();
    }

    bool empty() const { return elements.empty(); }
    size_t size() const { return elements.size(); }
};

// C++20 Concepts — constrain template parameters
std::integral auto add(std::integral auto a, std::integral auto b) {
    return a + b;
}

// Template specialization for std::string
template<>
std::string max_val<std::string>(std::string a, std::string b) {
    return (a.length() > b.length()) ? a : b;
}

int main() {
    // Function template — type deduction
    std::cout << "max(3, 7) = " << max_val(3, 7) << std::endl;
    std::cout << "max(3.14, 2.71) = " << max_val(3.14, 2.71) << std::endl;
    std::cout << "max(\"hello\", \"world\") = " << max_val(std::string("hello"), std::string("world")) << std::endl;

    // Class template with different types
    Stack<int> intStack;
    intStack.push(10);
    intStack.push(20);
    intStack.push(30);
    std::cout << "\nInt stack top: " << intStack.peek() << std::endl;
    std::cout << "Popped: " << intStack.pop() << std::endl;
    std::cout << "Size: " << intStack.size() << std::endl;

    Stack<std::string> strStack;
    strStack.push("Hello");
    strStack.push("World");
    std::cout << "\nString stack top: " << strStack.peek() << std::endl;

    // Concepts — compile-time type checking
    std::cout << "\nadd(5, 3) = " << add(5, 3) << std::endl;
    // add(5.5, 3.3);  // Compile error — not integral!

    // Template with auto (C++20)
    auto multiply = []<typename T>(T a, T b) { return a * b; };
    std::cout << "multiply(4, 5) = " << multiply(4, 5) << std::endl;
    std::cout << "multiply(2.5, 3.0) = " << multiply(2.5, 3.0) << std::endl;

    return 0;
}
