#include <iostream>
#include <fstream>
#include <string>
#include <vector>
#include <mutex>

// Manual resource management — error-prone
class BadFileHandler {
    FILE* file;
public:
    BadFileHandler(const char* path) {
        file = fopen(path, "w");
    }
    ~BadFileHandler() {
        if (file) fclose(file);  // What if constructor threw?
    }
    void write(const char* data) {
        fprintf(file, "%s", data);
    }
    // Problem: copy would double-close the file!
};

// RAII — safe resource management
class FileHandler {
    std::ofstream file;
public:
    FileHandler(const std::string& path) : file(path) {
        if (!file.is_open()) {
            throw std::runtime_error("Cannot open file: " + path);
        }
    }
    // Destructor automatically closes the file
    // No need for manual cleanup

    void write(const std::string& data) {
        file << data;
    }

    // Delete copy to prevent double-close
    FileHandler(const FileHandler&) = delete;
    FileHandler& operator=(const FileHandler&) = delete;

    // Allow move
    FileHandler(FileHandler&& other) noexcept = default;
    FileHandler& operator=(FileHandler&& other) noexcept = default;
};

// RAII lock guard
class BankAccount {
    double balance;
    mutable std::mutex mtx;
public:
    BankAccount(double initial) : balance(initial) {}

    void deposit(double amount) {
        std::lock_guard<std::mutex> lock(mtx);  // Lock acquired
        balance += amount;
        // Lock automatically released when lock_guard goes out of scope
    }

    bool withdraw(double amount) {
        std::lock_guard<std::mutex> lock(mtx);
        if (amount > balance) return false;
        balance -= amount;
        return true;
    }

    double getBalance() const {
        std::lock_guard<std::mutex> lock(mtx);
        return balance;
    }
};

int main() {
    // RAII file handling
    {
        FileHandler fh("output.txt");
        fh.write("Hello, RAII!\n");
        fh.write("Auto-closed on scope exit.\n");
    }  // File automatically closed here
    std::cout << "File written and closed automatically." << std::endl;

    // RAII with vectors — no manual delete needed
    {
        std::vector<int> data = {1, 2, 3, 4, 5};
        data.push_back(6);
        std::cout << "Vector size: " << data.size() << std::endl;
    }  // Vector memory automatically freed

    // RAII mutex locking
    BankAccount account(1000.0);
    account.deposit(500.0);
    account.withdraw(200.0);
    std::cout << "Balance: $" << account.getBalance() << std::endl;

    return 0;
}
