#include <iostream>
#include <memory>
#include <vector>
#include <string>

// Demonstrating move semantics
class Buffer {
    size_t size;
    int* data;
public:
    Buffer(size_t n) : size(n), data(new int[n]) {
        std::cout << "Constructed buffer of " << size << " ints" << std::endl;
    }

    // Move constructor — steal resources
    Buffer(Buffer&& other) noexcept : size(other.size), data(other.data) {
        other.size = 0;
        other.data = nullptr;  // Leave source in valid empty state
        std::cout << "Moved buffer" << std::endl;
    }

    // Move assignment
    Buffer& operator=(Buffer&& other) noexcept {
        if (this != &other) {
            delete[] data;
            size = other.size;
            data = other.data;
            other.size = 0;
            other.data = nullptr;
        }
        return *this;
    }

    // Delete copy — move-only type
    Buffer(const Buffer&) = delete;
    Buffer& operator=(const Buffer&) = delete;

    ~Buffer() { delete[] data; }

    size_t getSize() const { return size; }
};

// Smart pointer demo
class Node {
public:
    std::string name;
    std::shared_ptr<Node> next;
    std::weak_ptr<Node> prev;  // weak_ptr breaks circular reference

    Node(const std::string& n) : name(n) {
        std::cout << "Node " << name << " created" << std::endl;
    }
    ~Node() {
        std::cout << "Node " << name << " destroyed" << std::endl;
    }
};

int main() {
    // Move semantics
    std::cout << "=== Move Semantics ===" << std::endl;
    Buffer b1(1000);
    Buffer b2 = std::move(b1);  // Move, not copy
    std::cout << "b1 size: " << b1.getSize() << " (moved-from)" << std::endl;
    std::cout << "b2 size: " << b2.getSize() << " (moved-to)" << std::endl;

    // Move with vectors
    std::vector<std::string> v1 = {"hello", "world", "foo", "bar"};
    std::vector<std::string> v2 = std::move(v1);
    std::cout << "\nv1 empty: " << v1.empty() << std::endl;
    std::cout << "v2 size: " << v2.size() << std::endl;

    // unique_ptr — exclusive ownership
    std::cout << "\n=== unique_ptr ===" << std::endl;
    auto ptr = std::make_unique<Node>("unique_node");
    std::cout << "Owner: " << ptr->name << std::endl;
    // auto ptr2 = ptr;  // Compile error — can't copy unique_ptr!
    auto ptr2 = std::move(ptr);  // Transfer ownership
    std::cout << "New owner: " << ptr2->name << std::endl;
    std::cout << "Old ptr is null: " << (ptr == nullptr) << std::endl;

    // shared_ptr — shared ownership
    std::cout << "\n=== shared_ptr ===" << std::endl;
    auto node1 = std::make_shared<Node>("shared_node");
    std::cout << "Ref count: " << node1.use_count() << std::endl;
    {
        auto node2 = node1;  // Share ownership
        std::cout << "Ref count after copy: " << node1.use_count() << std::endl;
        node1->name = "modified";
        std::cout << "Both see: " << node2->name << std::endl;
    }  // node2 destroyed, ref count decreases
    std::cout << "Ref count after scope: " << node1.use_count() << std::endl;

    // weak_ptr — observe without owning
    std::cout << "\n=== weak_ptr ===" << std::endl;
    std::weak_ptr<Node> weak = node1;
    if (auto locked = weak.lock()) {
        std::cout << "Weak observed: " << locked->name << std::endl;
    }
    node1.reset();  // Release shared_ptr
    if (weak.expired()) {
        std::cout << "Node has been destroyed" << std::endl;
    }

    return 0;
}
